-- ----------------------------
-- Table structure for t_audit_log
-- ----------------------------
DROP TABLE IF EXISTS `t_audit_log`;
CREATE TABLE `t_audit_log`  (
                                `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                `user_id` int(11) NULL DEFAULT NULL COMMENT '操作用户ID，为空表示未登录用户',
                                `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户名',
                                `operation` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '操作类型',
                                `method` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '请求方法',
                                `params` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '请求参数',
                                `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'IP地址',
                                `create_time` datetime NOT NULL COMMENT '操作时间',
                                `status` tinyint(4) NOT NULL COMMENT '操作状态：0-失败，1-成功',
                                `message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '操作消息',
                                `hmac` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '日志HMAC值（HMAC-SM3）',
                                PRIMARY KEY (`id`) USING BTREE,
                                INDEX `user_id`(`user_id`) USING BTREE,
                                CONSTRAINT `t_audit_log_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `t_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2515 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '审计日志表' ROW_FORMAT = Dynamic;

