DROP TABLE IF EXISTS `t_child`;
CREATE TABLE `t_child`  (
                            `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                            `employee_id` int(11) NOT NULL COMMENT '员工ID',
                            `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '子女姓名',
                            `id_card` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '身份证号（SM4加密）',
                            `relation` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '关系',
                            `education_stage` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '教育阶段：PRESCHOOL-学前教育，PRIMARY-小学，JUNIOR-初中，HIGH-高中，UNIVERSITY-大学',
                            `create_time` datetime NOT NULL COMMENT '创建时间',
                            `update_time` datetime NOT NULL COMMENT '更新时间',
                            PRIMARY KEY (`id`) USING BTREE,
                            INDEX `employee_id`(`employee_id`) USING BTREE,
                            CONSTRAINT `t_child_ibfk_1` FOREIGN KEY (`employee_id`) REFERENCES `t_employee` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '子女表' ROW_FORMAT = Dynamic;

