                                 `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                 `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '部门名称',
