-- ----------------------------
-- Table structure for t_salary_config
-- ----------------------------
DROP TABLE IF EXISTS `t_salary_config`;
CREATE TABLE `t_salary_config`  (
                                    `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                    `employee_id` int(11) NOT NULL COMMENT '员工ID',
                                    `base_salary` decimal(10, 2) NOT NULL COMMENT '基本工资',
                                    `position_salary` decimal(10, 2) NOT NULL COMMENT '岗位工资',
                                    `lunch_subsidy` decimal(10, 2) NOT NULL COMMENT '午餐补贴',
                                    `full_attendance_bonus` decimal(10, 2) NOT NULL COMMENT '全勤奖',
                                    `overtime_hourly_rate` decimal(10, 2) NOT NULL COMMENT '加班小时工资',
                                    `status` tinyint(4) NOT NULL DEFAULT 1 COMMENT '状态：0-无效，1-有效',
                                    `create_time` datetime NOT NULL COMMENT '创建时间',
                                    `update_time` datetime NOT NULL COMMENT '更新时间',
                                    PRIMARY KEY (`id`) USING BTREE,
                                    INDEX `employee_id`(`employee_id`) USING BTREE,
                                    CONSTRAINT `t_salary_config_ibfk_1` FOREIGN KEY (`employee_id`) REFERENCES `t_employee` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '工资配置表' ROW_FORMAT = Dynamic;

