-- Records of t_salary_config
-- ----------------------------

-- ----------------------------
-- Table structure for t_salary_record
-- ----------------------------
DROP TABLE IF EXISTS `t_salary_record`;
CREATE TABLE `t_salary_record`  (
                                    `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                    `employee_id` int(11) NOT NULL COMMENT '员工ID',
                                    `department_id` int(11) NOT NULL COMMENT '部门ID',
                                    `year` int(11) NOT NULL COMMENT '年份',
                                    `month` int(11) NOT NULL COMMENT '月份',
                                    `base_salary` decimal(10, 2) NOT NULL COMMENT '基本工资',
                                    `position_salary` decimal(10, 2) NOT NULL COMMENT '岗位工资',
                                    `lunch_subsidy` decimal(10, 2) NOT NULL COMMENT '午餐补贴',
                                    `full_attendance_bonus` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '全勤奖',
                                    `overtime_salary` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '加班工资',
                                    `other_bonus` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '其他奖金',
                                    `gross_salary` decimal(10, 2) NOT NULL COMMENT '应发工资（税前）',
                                    `social_insurance` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '社保扣除',
                                    `housing_fund` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '公积金扣除',
                                    `special_deduction` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '专项附加扣除',
                                    `tax_amount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '个人所得税',
                                    `absence_deduction` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '缺勤扣款',
                                    `other_deduction` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '其他扣款',
                                    `net_salary` decimal(10, 2) NOT NULL COMMENT '实发工资（税后）',
                                    `note` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
                                    `status` tinyint(4) NOT NULL DEFAULT 1 COMMENT '状态：0-作废，1-正常',
                                    `create_time` datetime NOT NULL COMMENT '创建时间',
                                    `update_time` datetime NOT NULL COMMENT '更新时间',
                                    PRIMARY KEY (`id`) USING BTREE,
                                    INDEX `department_id`(`department_id`) USING BTREE,
                                    INDEX `idx_salary_year_month`(`year`, `month`) USING BTREE,
                                    INDEX `idx_salary_employee_id`(`employee_id`) USING BTREE,
                                    CONSTRAINT `t_salary_record_ibfk_1` FOREIGN KEY (`employee_id`) REFERENCES `t_employee` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
                                    CONSTRAINT `t_salary_record_ibfk_2` FOREIGN KEY (`department_id`) REFERENCES `t_department` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '月工资表' ROW_FORMAT = Dynamic;

