-- Records of t_salary_record
-- ----------------------------

-- ----------------------------
-- Table structure for t_special_deduction
-- ----------------------------
DROP TABLE IF EXISTS `t_special_deduction`;
CREATE TABLE `t_special_deduction`  (
                                        `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
                                        `employee_id` int(11) NOT NULL COMMENT '员工ID',
                                        `year` int(11) NOT NULL COMMENT '年份',
                                        `children_education` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '子女教育',
                                        `continuing_education` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '继续教育',
                                        `housing_loan` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '住房贷款利息',
                                        `housing_rent` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '住房租金',
                                        `elderly_care` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '赡养老人',
                                        `medical_expense` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '大病医疗',
                                        `child_care` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '婴幼儿照护',
                                        `create_time` datetime NOT NULL COMMENT '创建时间',
                                        `update_time` datetime NOT NULL COMMENT '更新时间',
                                        PRIMARY KEY (`id`) USING BTREE,
                                        INDEX `employee_id`(`employee_id`) USING BTREE,
                                        CONSTRAINT `t_special_deduction_ibfk_1` FOREIGN KEY (`employee_id`) REFERENCES `t_employee` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '专项附加扣除设置表' ROW_FORMAT = Dynamic;

